import React from "react";
import { Swiper, SwiperSlide } from "swiper/react";
import "swiper/css";
import "swiper/css/navigation";
import { Navigation } from "swiper/modules";

const HomeCat = () => {
  return (
    <section className="homeCat">
      <div className="container">
        <Swiper
          slidesPerView={6}
          spaceBetween={0}
          pagination={{
            clickable: true,
          }}
          navigation={true}
          modules={[Navigation]}
          className="mySwiper"
        >
          <SwiperSlide>
            <div className="item">
              <img src="https://cdn-icons-png.flaticon.com/128/4659/4659379.png" />
            </div>
          </SwiperSlide>
        </Swiper>
      </div>
    </section>
  );
};
export default HomeCat;
